const { readdirSync } = require('fs');
const path = require('path');

const { SCRIPT_EQUIVALENT_EXTENSIONS } = require('../constants/file');

/**
 * @param {string | undefined} filePath
 * @param {string | undefined} pagesDir
 * @param {string | undefined} pagesBuildDir
 */
const getTranspiledPath = (filePath, pagesDir, pagesBuildDir) => {
  if (!filePath) {
    return null;
  }

  try {
    const transpiledFilePath = filePath.replace(pagesDir, pagesBuildDir);

    const dirName = path.dirname(transpiledFilePath);
    const fileName = path.basename(transpiledFilePath);
    const sourceExt = path.extname(fileName);
    const validExtensions = SCRIPT_EQUIVALENT_EXTENSIONS[sourceExt];
    // eslint-disable-next-line security/detect-non-literal-fs-filename
    const filesInDir = readdirSync(dirName);

    // eslint-disable-next-line no-restricted-syntax
    for (const file of filesInDir) {
      const foundFile = validExtensions.some(
        (ext) => fileName.replace(sourceExt, ext) === file,
      );

      if (foundFile) {
        return path.join(dirName, file);
      }
    }

    return null;
  } catch (error) {
    return null;
  }
};

module.exports = {
  getTranspiledPath,
};
